section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/java-spring-boot.json",
  "type": "object",
  "required": [
    "controller_class",
    "service_class",
    "repository_interface",
    "dto_used",
    "transactional_on_service",
    "actuator_enabled"
  ],
  "properties": {
    "controller_class": {
      "type": "string",
      "pattern": "^[A-Z][A-Za-z0-9]+Controller$"
    },
    "service_class": {
      "type": "string",
      "pattern": "^[A-Z][A-Za-z0-9]+Service$"
    },
    "repository_interface": {
      "type": "string",
      "pattern": "^[A-Z][A-Za-z0-9]+Repository$"
    },
    "dto_used": {
      "type": "boolean",
      "const": true
    },
    "transactional_on_service": {
      "type": "boolean",
      "const": true
    },
    "transactional_on_controller": {
      "type": "boolean",
      "const": false
    },
    "constructor_injection": {
      "type": "boolean",
      "const": true
    },
    "actuator_enabled": {
      "type": "boolean",
      "const": true
    }
  },
  "additionalProperties": false
}
